import{_ as e,c as a,o as l,ah as i}from"./chunks/framework.BZunv3CL.js";const f=JSON.parse('{"title":"申请和安装许可证","description":"","frontmatter":{},"headers":[],"relativePath":"zh_CN/installation/license-install/license-install.md","filePath":"zh_CN/installation/license-install/license-install.md"}'),r={name:"zh_CN/installation/license-install/license-install.md"};function s(n,t,d,c,o,p){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="申请和安装许可证" tabindex="-1">申请和安装许可证 <a class="header-anchor" href="#申请和安装许可证" aria-label="Permalink to “申请和安装许可证”">​</a></h1><p>GridBeat 是一个开源项目。我们鼓励社区开发自己的插件模块。</p><p>核心架构，仪表板和一些驱动模块（例如 modbus-tcp，mqtt 和 eKuiper 等）是在 LGPLv3 许可下开源的。您无需安装 EMQ 许可证即可运行这些开源模块。</p><p>对于商业模块，GridBeat 提供了 30 个点（30 个连接和 30 个数据标签）的免费额度。您可在不安装 EMQ 许可证的情况下，运行这些商业模块。超出免费额度后，则必须安装有效的试用版或官方 EMQ 许可证。</p><p>试用的 EMQ 许可证可从<a href="https://www.emqx.com/zh/apply-licenses/gridbeat" target="_blank" rel="noreferrer">官方网站</a>上下载 。所有可用的模块都可以在 100 个连接和 1,000 个数据标签的限制下试用 15 天。 如果试用 EMQ 许可证过期，您可以通过我们的官网重新申请试用 EMQ 许可证。 但是，一个邮箱最多只能申请两次试用许可证。</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>官网申请试用许可证时，必须使用硬件标识进行设备的绑定。您可直接<a href="https://www.emqx.com/zh/contact?product=gridbeat" target="_blank" rel="noreferrer">联系我们</a>申请不需要硬件标识绑定设备的许可证，或申请正式许可证。</p></div><h2 id="第一步-查看硬件标志" tabindex="-1">第一步，查看硬件标志 <a class="header-anchor" href="#第一步-查看硬件标志" aria-label="Permalink to “第一步，查看硬件标志”">​</a></h2><p>点击右上角 <strong>系统信息-&gt;关于</strong> 查看硬件标志并将其拷贝。</p><h2 id="第二步-申请许可证" tabindex="-1">第二步，申请许可证 <a class="header-anchor" href="#第二步-申请许可证" aria-label="Permalink to “第二步，申请许可证”">​</a></h2><p>进入<a href="https://www.emqx.com/zh/apply-licenses/gridbeat" target="_blank" rel="noreferrer">官方网站</a>填写相关信息申请许可证，许可证将发送到您的邮箱。</p><h2 id="第三步-安装许可证" tabindex="-1">第三步，安装许可证 <a class="header-anchor" href="#第三步-安装许可证" aria-label="Permalink to “第三步，安装许可证”">​</a></h2><p>点击右上角 <strong>系统信息-&gt;License</strong>，上传邮箱中接受到的许可证文件（.lic 文件）并提交。</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>申请有效的 License 时需要填写硬件标志。</p><p>在未上传 License 或者 License 过期时，商业版的可插拔模块是无法使用的。</p><p>用户可以在页面点击<code>申请</code>申请试用许可证，或点击<code>联系我们</code>联系我们的销售代表购买商业许可证。</p></div><h2 id="第四步-查看许可证详细信息" tabindex="-1">第四步，查看许可证详细信息 <a class="header-anchor" href="#第四步-查看许可证详细信息" aria-label="Permalink to “第四步，查看许可证详细信息”">​</a></h2><p>在 License 成功上传后，页面将展示 License 信息。</p><p>许可证页面详细信息包括以下方面：</p><table tabindex="0"><thead><tr><th style="text-align:left;">内容</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">生效日期</td><td style="text-align:left;">GridBeat 申请 License 生效的时间</td></tr><tr><td style="text-align:left;">失效日期</td><td style="text-align:left;">GridBeat 可使用的截止日期，如果 License 过期，系统将无法正常工作，您必须重新获取新的有效的 License，重新上传 License</td></tr><tr><td style="text-align:left;">节点数限制</td><td style="text-align:left;">GridBeat 可创建节点总数的最大值，一个节点指的是一个南向设备或者是一个北向应用</td></tr><tr><td style="text-align:left;">Tag 数目限制</td><td style="text-align:left;">GridBeat 可创建的所有点位总和的最大值</td></tr><tr><td style="text-align:left;">可用的 Plugin</td><td style="text-align:left;">GridBeat 已授权的插件。每个商业插件模块都可以在 EMQ 许可证中独立授权</td></tr></tbody></table>',17)])])}const b=e(r,[["render",s]]);export{f as __pageData,b as default};
